const Card = ({ text, onDrop, id, image, changeArr, scrollOffset, onFlipComplete }) => {
    const translateX = useRef(new Animated.Value(0)).current;
    const translateY = useRef(new Animated.Value(0)).current;
    const lastOffset = useRef({ x: 0, y: 0 }).current;
    const [isInCell, setIsInCell] = useState(false)
    const cardRef = useRef();
    const [cardPosX, setCardPosX] = useState(0)
    const [cardPosY, setCardPosY] = useState(0)
    const [cardOpacity, setCardOpacity] = useState(1)
    const rotateY = useRef(new Animated.Value(0)).current;
    const [flipped, setFlipped] = useState(false);
    const cardScale = useRef(new Animated.Value(1)).current;

    const rotateYInterpolated = rotateY.interpolate({
      inputRange: [0, 0.5, 1],
      outputRange: ['0deg', '90deg', '180deg']
    });

    const cardScaleInterpolated = cardScale.interpolate({
      inputRange: [0, 0.5, 1],
      outputRange: [1, 1.2, 1]
    });

    useEffect(() => {
      rotateY.addListener(({ value }) => {
          if (value >= 0.5 && !flipped) {
              setFlipped(true);
          } else if (value < 0.5 && flipped) {
              setFlipped(false);
          }
      });
      return () => {
          rotateY.removeAllListeners();
      };
  }, [flipped]);

    useEffect(() => {
        // Установите начальную позицию карты, если она предоставлена
        cardRef.current.measureInWindow((x, y, width, height) => {
            const initialPosX = x; // Начальная позиция X карты
            const initialPosY = y; // Начальная позиция Y карты
            console.log('x ', initialPosX, 'y ', initialPosY)
            setCardPosX(x)
            setCardPosY(y)
            lastOffset.x = x
            lastOffset.y = y
          });
    }, [cardRef.current]);
  
    const flipCard = (pos) => {
      Animated.timing(cardScale, {
        toValue: 0,
        duration: 600,
        useNativeDriver: true
      }).start()
      Animated.timing(rotateY, {
          toValue: flipped ? 0 : 1,
          duration: 600,
          useNativeDriver: true
      }).start(() => {
          // changeArr(pos.x + 20, pos.y - 15, text, id, pos.cellIndex)
          setCardOpacity(0)
          onFlipComplete(id);
      });
    };

    const onGestureEvent = Animated.event(
      [
        {
          nativeEvent: !isInCell ? {
            translationX: translateX,
            translationY: translateY,
          } : {}
        },
      ],
      { useNativeDriver: true }
    );

  
    const onHandlerStateChange = event => {
        if (event.nativeEvent.oldState === State.ACTIVE && !isInCell) {
            const { translationX } = event.nativeEvent;
            const { translationY } = event.nativeEvent;
            lastOffset.x += translationX - scrollOffset;
            lastOffset.y += translationY;
            const isDroppedOnCell = onDrop(lastOffset, cardPosY).isOn;
            const droping = onDrop(lastOffset, cardPosY)
            if (isDroppedOnCell) {
                // Обновляем позицию карты, если она попала в ячейку
                setIsInCell(true)
                Animated.spring(translateX, {
                    toValue: droping.x - cardPosX + scrollOffset + 20,
                    useNativeDriver: true,
                }).start(() => {
                    lastOffset.x = droping.x - cardPosX + scrollOffset + 20;
                    translateX.setOffset(lastOffset.x);
                    translateX.setValue(0);
                });
                Animated.spring(translateY, {
                    toValue: droping.y - cardPosY + 20,
                    useNativeDriver: true,
                }).start(() => {
                    lastOffset.y = droping.y - cardPosY + 20;
                    translateY.setOffset(lastOffset.y);
                    translateY.setValue(0);
                    changeArr(droping.x, droping.y - cardPosY, text, id, droping.cellIndex, droping.type)
                    flipCard(droping)
                });
                
            } else {
                // Возвращаем карту на исходную позицию, если она не попала в ячейку
                isInCell && translateX.setValue(lastOffset.x)
                isInCell && translateX.setOffset(0)
                isInCell && translateY.setValue(lastOffset.y)
                isInCell && translateY.setOffset(0)
                Animated.spring(translateX, {
                    toValue: 0,
                    useNativeDriver: true,
                }).start();
                Animated.spring(translateY, {
                    toValue: 0,
                    useNativeDriver: true,
                }).start(() => {
                    lastOffset.x = cardPosX;
                    lastOffset.y = cardPosY;
                    translateX.setOffset(0);
                    translateY.setOffset(0);
                    translateX.setValue(0);
                    translateY.setValue(0);
                });
                // Сбросить смещение и значение
                
            }
        }
    };
  
    return (
      <PanGestureHandler
        onGestureEvent={onGestureEvent}
        onHandlerStateChange={onHandlerStateChange}
      >
        <Animated.View
          ref={cardRef}
          style={[
            styles.cardOne,
            {
              transform: [{ translateX }, { translateY }, {rotateY: rotateYInterpolated}, {scale: cardScaleInterpolated}],
            },
            {zIndex: 1000, borderRadius: 10, overflow: 'hidden', opacity: cardOpacity}
          ]}
        >
            <BackView text={text} image={image} />
            <FrontView opacity={flipped==true ? 0 : 1} />
        </Animated.View>
      </PanGestureHandler>
    );
  };

  const CardCelled = ({text, image, posx=0, posy=0, opacity}) => {
    return(
      <Animated.View
          // ref={cardRef}
          style={[
            styles.cardOne,
            {
              transform: [{ translateX: posx }, { translateY: posy }, {scaleX: -1}],
              opacity: opacity
            },
            {zIndex: 1, borderRadius: 10, overflow: 'hidden', position: 'absolute', left: 0, bottom: 35}
          ]}
        >
            <BackView text={text} image={image} />
            <FrontView opacity={0} />
        </Animated.View>
    )
  }

  const CardChoosing = ({text, image, elevation=0}) => {
    return(
      <View
          // ref={cardRef}
          style={[
            styles.cardOne,
            {
              opacity: 1
            },
            {borderRadius: 10, overflow: 'hidden'}
          ]}
        >
            {/* <BackView text={text} image={image} /> */}
            <FrontView opacity={1} />
        </View>
    )
  }

  const Cell = ({ index, text, type, fSize, updateCellLayouts }) => {
    const cellRef = useRef();
  
    useEffect(() => {
        setTimeout(() => {
            cellRef.current.measureInWindow((x, y, width, height) => {
                if (x != 0 || y != 0) {
                  updateCellLayouts({ index, type, x: x - 20, y: y - 20, width: width, height: height })
                }
              });
        }, 100)
    }, [cellRef.current]);
    return (
      <View ref={cellRef} style={{ width: SCREEN_HEIGHT / 6.2 / 1.59, height: SCREEN_HEIGHT / 6.2, borderRadius: 10, overflow: 'hidden',
       backgroundColor: '#223A4B', justifyContent: 'center', alignItems: 'center', padding: 2 }}>
        <Text
          style={{ color: '#fff', fontSize: fSize, textAlign: 'center', fontFamily: 'SftMedium' }}
        >{text}</Text>
      </View>
    );
  };

  const CellInstruction = ({ index, text, fSize }) => {

    return (
      <View style={{ width: SCREEN_WIDTH / 4.7, height: (SCREEN_WIDTH / 4.7) * 1.59, borderRadius: 10, overflow: 'hidden',
       backgroundColor: '#223A4B', justifyContent: 'center', alignItems: 'center' }}>
        <Text
          style={{ color: '#fff', fontSize: fSize, textAlign: 'center', fontFamily: 'SftMedium' }}
        >{text}</Text>
      </View>
    );
  };

  

