    const handleDrop = (cardPosition, cardPosY, cardIndex) => {
        console.log('length', cellLayouts.length)
        const adjustedX = cardPosition.x
        const droppedCell = cellLayouts.find(cell => 
          adjustedX > cell.x &&
          adjustedX < cell.x + cell.width &&
          cardPosition.y > cell.y &&
          cardPosition.y < cell.y + cell.height
        );
        const cellUsed = arrCardsInCell.find(card => 
          adjustedX + 20 > card.posx &&
          adjustedX + 20 < card.posx + (SCREEN_HEIGHT / 6.2 / 1.59) + 20 &&
          cardPosition.y + 20 > card.posy + SCREEN_HEIGHT - 35 - (SCREEN_HEIGHT / 6.2) - 20 &&
          cardPosition.y + 20 < card.posy  + SCREEN_HEIGHT - 35
        );
        console.log('droppedcell ', droppedCell)
        if (cellUsed) {
          console.log('is cell used? ', cellUsed)
        }
        
        
        if (droppedCell && !cellUsed) {
          // Карта попала в ячейку, обновите состояние или выполните другие действия
          setDisplayFrontModal(true)
          return {isOn: true, x: droppedCell.x, y: droppedCell.y, cellIndex: droppedCell.index, type: droppedCell.type};
        }
        return {isOn: false};
      };

